/**
 * Is this shape a valid inference or a known mistake?
 */
export class FormKind extends Union {
    constructor(tag, fields) {
        super();
        this.tag = tag;
        this.fields = fields;
    }
    cases() {
        return ["ValidForm", "FallacyForm"];
    }
}

export function FormKind_$reflection() {
    return union_type("Meticulous.InferenceRules.FormKind", [], FormKind, () => [[], []]);
}

export class ArgumentForm extends Record {
    constructor(Name, Title, Aka, Premises, Conclusion, Kind, Note) {
        super();
        this.Name = Name;
        this.Title = Title;
        this.Aka = Aka;
        this.Premises = Premises;
        this.Conclusion = Conclusion;
        this.Kind = Kind;
        this.Note = Note;
    }
}

export function ArgumentForm_$reflection() {
    return record_type("Meticulous.InferenceRules.ArgumentForm", [], ArgumentForm, () => [["Name", string_type], ["Title", string_type], ["Aka", string_type], ["Premises", list_type(Formula_$reflection())], ["Conclusion", Formula_$reflection()], ["Kind", FormKind_$reflection()], ["Note", string_type]]);
}

